@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge @GetPriorityClass()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (CanMoveLeft)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
    </div>
    <div class="mb-2">
        <select class="form-select form-select-sm" @bind="priority">
            <option value="">Select Priority</option>
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="mb-2">
        <input type="date" class="form-control form-control-sm" @bind="dueDate" />
    </div>
    <div class="d-flex gap-2">
        <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn btn-sm btn-secondary" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="text-danger mt-1 small">@errorMessage</div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "";
    private DateTime dueDate = DateTime.Today;
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@ColumnName <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight" />
        }
    </div>
    <div class="kanban-column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleTaskCreated" OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showAddForm;

    private async Task HandleMoveLeft(int taskId)
    {
        await OnTaskMoved.InvokeAsync((taskId, "left"));
    }

    private async Task HandleMoveRight(int taskId)
    {
        await OnTaskMoved.InvokeAsync((taskId, "right"));
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        showAddForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="board-search-bar">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

