        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
    </div>
    <div class="mb-2">
        <select class="form-select form-select-sm" @bind="priority">
            <option value="">Select Priority</option>
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="mb-2">
        <input type="date" class="form-control form-control-sm" @bind="dueDate" />
    </div>
    <div class="d-flex gap-2">
        <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn btn-sm btn-secondary" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="text-danger mt-1 small">@errorMessage</div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "";
    private DateTime dueDate = DateTime.Today;
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

