@* A single Kanban column displaying its header, task cards, and an add-task form toggle *@

<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@ColumnName <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight" />
        }
    </div>
    <div class="kanban-column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleTaskCreated" OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskCreated { get; set; }

    private bool showAddForm;

    private async Task HandleMoveLeft(int taskId)
    {
        await OnTaskMoved.InvokeAsync((taskId, "left"));
    }

    private async Task HandleMoveRight(int taskId)
    {
        await OnTaskMoved.InvokeAsync((taskId, "right"));
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync((newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate, ColumnName));
        showAddForm = false;
    }
}

