@page "/board"
@rendermode InteractiveServer
@using sv_b684576232a44db295aa3175dd9da682.Components.Pages.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="kanban-board">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            var tasks = FilteredTasksForStatus(col);
            <KanbanColumn ColumnName="@col"
                          Tasks="tasks"
                          CanMoveLeft="colIndex > 0"
                          CanMoveRight="colIndex < columns.Length - 1"
                          OnTaskMoved="HandleTaskMoved"
                          OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private readonly string[] columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private List<TaskItem> FilteredTasksForStatus(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state to avoid a full reload
            var idx = allTasks.FindIndex(t => t.Id == task.Id);
            allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) newTask)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
            // The service creates with default status; override if the column differs
            if (created.Status != newTask.Status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, newTask.Status);
                created = created with { Status = newTask.Status };
            }
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

